from __future__ import annotations

from pathlib import Path
import base64

HTML_B64 = """"""


def main() -> None:
    output_path = Path(__file__).with_name("index.html")
    output_path.write_bytes(base64.b64decode(HTML_B64))
    print(f"Wrote {output_path}")


if __name__ == "__main__":
    main()